class Track:
    _title: str
    _artist: str
    _duration: float

    def __init__(self, title: str, artist: str, duration: float):
        self._title = title
        self._artist = artist
        self._duration = duration

    property get title(self) -> str:
        return self._title

    property get artist(self) -> str:
        return self._artist

    property get duration(self) -> float:
        return self._duration

    @override def __str__(self) -> str:
        return self._title + " by " + self._artist + " [" + str(self._duration) + " min]"

    @override def __eq__(self, other: object) -> bool:
        if not isinstance(other, Track):
            return False
        return self._title == other._title and self._artist == other._artist

    @override def __hash__(self) -> int:
        return hash(self._title) + hash(self._artist)

