from track import Track

class Playlist:
    _name: str
    _tracks: list[Track]

    def __init__(self, name: str):
        self._name = name
        self._tracks = []

    property get name(self) -> str:
        return self._name

    property get track_count(self) -> int:
        return len(self._tracks)

    property get total_duration(self) -> float:
        total: float = 0.0
        for track in self._tracks:
            total += track.duration
        return total

    def add_track(self, track: Track) -> None:
        self._tracks.append(track)

    def get_tracks_by_artist(self, artist: str) -> list[Track]:
        result: list[Track] = []
        for track in self._tracks:
            if track.artist == artist:
                result.append(track)
        return result

    def create_empty(name: str) -> Playlist:
        return Playlist(name)
